parameters.jsCode:
return items.map(item => {
  let raw = item.json.output;

  if (!raw) {
    return { json: {} };
  }

  // 1. Убираем ```json и ```
  raw = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '');

  let data;
  try {
    // 2. Парсим JSON из строки
    data = JSON.parse(raw);
  } catch (error) {
    throw new Error('Ошибка парсинга JSON: ' + error.message + '\nСтрока: ' + raw.slice(0, 200));
  }

  // 3. Форматируем и создаём бинарник
  const jsonString = JSON.stringify(data, null, 2);
  const binaryData = Buffer.from(jsonString, 'utf8');

  return {
    json: {}, // json можно оставить пустым
    binary: {
      data: {
        data: binaryData.toString('base64'),
        mimeType: 'application/json',
        fileName: 'workflow.json',
      }
    }
  };
});

